          commitments == other.commitments;
}

/// Shared delegation/voting round context passed across the FRB boundary.
///
/// This bundles the reusable round and wallet scope required by delegation setup,
/// proving, and keystone request flows.
class ApiVotingRoundContext {
  final String dbPath;
  final String lightwalletdUrl;
  final String network;
  final VotingRoundParams roundParams;
  final String roundName;
  final String? sessionJson;
  final String accountUuid;
  final int? maxRealNotesPerBundle;

  const ApiVotingRoundContext({
    required this.dbPath,
    required this.lightwalletdUrl,
    required this.network,
    required this.roundParams,
    required this.roundName,
    this.sessionJson,
    required this.accountUuid,
    this.maxRealNotesPerBundle,
  });

  @override
  int get hashCode =>
      dbPath.hashCode ^
      lightwalletdUrl.hashCode ^
      network.hashCode ^
      roundParams.hashCode ^
      roundName.hashCode ^
      sessionJson.hashCode ^
      accountUuid.hashCode ^
      maxRealNotesPerBundle.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ApiVotingRoundContext &&
          runtimeType == other.runtimeType &&
          dbPath == other.dbPath &&
          lightwalletdUrl == other.lightwalletdUrl &&
          network == other.network &&
          roundParams == other.roundParams &&
          roundName == other.roundName &&
          sessionJson == other.sessionJson &&
          accountUuid == other.accountUuid &&
          maxRealNotesPerBundle == other.maxRealNotesPerBundle;
}

/// Parsed fields from a Keystone-signed voting PCZT.
class ParsedSignedVotingPczt {
  /// ZIP-244 sighash extracted from the signed PCZT.
  final Uint8List sighash;

  /// Orchard SpendAuth signature extracted from the signed PCZT.
  final Uint8List spendAuthSig;

  const ParsedSignedVotingPczt({
    required this.sighash,
    required this.spendAuthSig,
  });

  @override
  int get hashCode => sighash.hashCode ^ spendAuthSig.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is ParsedSignedVotingPczt &&
          runtimeType == other.runtimeType &&
          sighash == other.sighash &&
          spendAuthSig == other.spendAuthSig;
}

class VotingConfigResolution {
  final ResolvedVotingConfig config;
  final ConfigSwitchKind switchKind;

  const VotingConfigResolution({
    required this.config,
    required this.switchKind,
  });

  @override
  int get hashCode => config.hashCode ^ switchKind.hashCode;

  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      other is VotingConfigResolution &&
          runtimeType == other.runtimeType &&
          config == other.config &&
          switchKind == other.switchKind;
}
